def gen(rng, size):
    import string
    n = min(size, 500)
    chars = []
    letter_count = 0
    for _ in range(n):
        if letter_count > 0 and rng.random() < 0.3:
            chars.append('*')
            letter_count -= 1
        else:
            chars.append(rng.choice(string.ascii_lowercase[:8]))
            letter_count += 1
    return [''.join(chars)]

