class Solution:
    def clearStars(self, s):
        # Simulate the 26-stack approach as a reference
        stacks = [[] for _ in range(26)]
        removed = [False] * len(s)
        for i, c in enumerate(s):
            if c == '*':
                removed[i] = True
                for j in range(26):
                    if stacks[j]:
                        removed[stacks[j].pop()] = True
                        break
            else:
                stacks[ord(c) - ord('a')].append(i)
        return ''.join(s[i] for i in range(len(s)) if not removed[i])

