solutions.javascript:
var clearStars = function(s) {
    const stacks = Array.from({length: 26}, () => []);
    const removed = new Array(s.length).fill(false);
    for (let i = 0; i < s.length; i++) {
        const c = s[i];
        if (c === '*') {
            removed[i] = true;
            for (let j = 0; j < 26; j++) {
                if (stacks[j].length > 0) {
                    removed[stacks[j].pop()] = true;
                    break;
                }
            }
        } else {
            stacks[s.charCodeAt(i) - 97].push(i);
        }
    }
    let res = '';
    for (let i = 0; i < s.length; i++) {
        if (!removed[i]) res += s[i];
    }
    return res;
};
